	; CHECK KEYBOARD	LDA 1 SKEY	AND# 0 1 SNR		; "S" KEY?	 JSR PRINTSUM		; PRINT ERROR SUMMARY	LDA 0 @pKBDAD1	LDA 1 BLANKMIDKEY	AND# 0 1 SZR		; "BLANK MIDDLE" KEY?	 JMP L1			; NO	LDA 1 CURSORFLAG	COM 1 1	STA 1 CURSORFLAGL1:	LDA 0 ALTO2		; TEST MEMORY FAST	SNZ 0 0	 JSRII ppA1TMF	JSRII ppA2TMF	 NOP	ISZ BLOCKS	 NOP	LDA 0 DOSUMMARY	SZ 0 0			; TIME TO REPORT TEST RESULTS?	 JSR PRINTSUM		; YES	MKZERO 0 0	STA 0 DOSUMMARY	LDA 0 DOSLOWTESTS	SNZ 0 0	 JMP LOOP	MKZERO 0 0	STA 0 DOSLOWTESTS	LDA 0 ALTO2		; TEST MEMORY SLOW	SNZ 0 0	 JSRII ppA1TMS	JSRII ppA2TMS	 NOP	JSRII ppRAMTEST		; RAM TEST IS SLOW	JMP LOOPC77:		77BLOCKS:		0		; TOTAL TESTS MOD 2^16CURSORXMAX:	1100		; MAX CURSOR X VALUECURSORYMAX:	1400		; MAX CURSOR Y VALUEpCURSORX:	426		; CURSOR X LOCpCURSORY:	427		; CURSOR Y LOCCURSORFLAG:	-1		; TRUE => WALK, FALSE => FLINGppA1TMF:	A1TMFppA2TMF:	A2TMFppA1TMS:	A1TMSppA2TMS:	A2TMSppRAMTEST:	RAMTEST;-----------------------------------------------------------------------------PRINTSUM:;-----------------------------------------------------------------------------	STA 3 PSRET	JSRII ppRESTORE		; SET UP DISPLAY	LDA 0 VERSION	STA 0 PS0	JSR @PMSGPS0:	 0	JSR @PMSG1	 .TXT "*NAlto "	JSR @PMSG1	 .TXT "I"	LDA 0 ALTO2	SNZ 0 0	 JMP PS1	JSR @PMSG1	 .TXT "I"PS1:	LDA 1 @pEHLOC	JSR @POCT	LDA 0 XMFLAG	SZ 0 0	 JMP PS2	JSR @PMSG1	 .TXT ", 64K"	JMP PS6PS2:	MKONE 1 1	SE 0 1	 JMP PS3	JSR @PMSG1	 .TXT ", XM 64K"	JMP PS6PS3:	INC 1 1	SE 0 1	 JMP PS4	JSR @PMSG1	 .TXT ", XM 128K"	JMP PS6PS4:	INC 1 1	SE 0 1	 JMP PS5	JSR @PMSG1	 .TXT ", XM 192K"	JMP PS6PS5:	JSR @PMSG1	 .TXT ", XM 256K"PS6:	LDA 0 RAMFLAG	SZ 0 0	 JMP PS7	JSR @PMSG1	 .TXT ", No Ram"	JMP PS9pKBDAD1:	177035		; KEYBOARD WORD POINTERSKEY:		1B4		; THE BIT FOR THE KEY "S"BLANKTOPKEY:	1		; THE BIT FOR THE KEY "BLANK TOP"BLANKMIDKEY:	2		; THE BIT FOR THE KEY "BLANK MIDDLE"PSRET:		0pEHLOC:		610		; ETHER HOST LOCBMASK:		14pBANKREG0:	177740pp