E NONZERO	LDA 2 pDCBR	LDA 1 M6PE2:	LDA 0 0 2		; PARITY R-REGISTER	SZ 0 0			; BEING ZERO IS SUSPICIOUS	 JMP PE1		; NON-ZERO MEANS THE PE WAS REAL	INC 2 2	INC 1 1 SZR		; HAVE WE LOOKED AT ALL OF THEM?	 JMP PE2		; NO	ISZ SOFTPEC		; SOFTWARE BUG	 JMP IRET	DSZ SOFTPEC		; CANT SKIP	 JMP IRETPE1:	LDA 0 @pACT		; DISABLE PARITY INTERRUPTS	MOVR 0 0	MOVZL 0 0	STA 0 @pACT	EIR			; BUT ALLOW OTHER INTERRUPTS	LDA 0 ALTO2	SNZ 0 0			; CALL ERROR ANALYZER	 JSRII ppA1PEINT	JSRII ppA2PEINT	 NOP; COME HERE TO DISMISS THE PARITY INTERRUPTIRET:	DIR	LDA 0 @pWW		; CLEAR PARITY WAKEUPS WAITING	MOVR 0 0	MOVZL 0 0	STA 0 @pWW	LDA 0 @pACT		; ENABLE PARITY INTERRUPTS	MOVR 0 0	MOVOL 0 0	STA 0 @pACT; ZERO THE PARITY ERROR DUMP AREA.  IF IT IS STILL ZERO ON THE; NEXT PE INTERRUPT, THEN IT WAS CAUSED BY A SOFTWARE BUG.	MKZERO 0 0	LDA 1 pSAD	LDA 3 M6	BLKS	LDA 0 PEPC		; RESTORE MACHINE STATE	STA 0 @pPCLOC	LDA 0 PECY	MOVL 0 0	LDA 3 PEAC3	LDA 2 PEAC2	LDA 1 PEAC1	LDA 0 PEAC0	BRIpPCLOC:		500		;-> INTERRUPT PCpDCBR:		614		;-> PARITY DUMP AREAppA1PEINT:	A1PEINTppA2PEINT:	A2PEINTM6:		-6SOFTPEC:	0	.ZREL; MACHINE STATE SAVED HERE ON PARITY INTERRUPTPEAC0:		0		; AC0PEAC1:		0		; AC1PEAC2:		0		; AC2PEAC3:		0		; AC3PECY:		0		; CARRYPEPC:		0		; PCpIRET:		IRET		;-> CODE TO DISMISS PARITY INTERRUPT	.NREL;-----------------------------------------------------------------------------.TIMERINT:			; VERTICAL FIELD INTERRUPT;-----------------------------------------------------------------------------	STA 0 TS0	STA 1 TS1	STA 2 TS2	STA 3 TS3	MOVL 0 0	STA 0 TC	ISZ VINT		; USED BY ALTO1 DTEST	 NOP; THIS CODE DECIDES WHEN TO BROADCAST A SUMMARY OF THE TEST RESULTS.; IT GENERATES ITS FIRST SUMMARY AFTER 1 MINUTE, THEN EVERY 128 MINUTES.; IF AN ERROR IS REPORTED, THEN IT IMMEDIATELY GENERATES A SUMMARY,; THEN ANOTHER AFTER 1 MINUTE, THEN 2 MINUTES LATER,; THEN 4 MINUTES AFTER THAT, ... UP TO A MAX OF 128 MINUTES.; WHEN IT REACHES 128,